import{_ as e,a as s}from"./chunks/electron-logo.opFE0ztr.js";import{_ as o,c as n,o as a,ah as r}from"./chunks/framework.RCw5T9E9.js";const f=JSON.parse('{"title":"Installation","description":"","frontmatter":{"title":"Installation"},"headers":[],"relativePath":"install.md","filePath":"install.md"}'),i={name:"install.md"};function l(d,t,c,h,p,g){return a(),n("div",null,[...t[0]||(t[0]=[r('<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><p>Vue Inspector is available in more than one launch mode so you can use it across environments and browsers.</p><p>The right mode depends on environment constraints, security policy, and how you prefer to work.</p><div class="install-options"><a class="install-option-card" href="./extension"><span class="install-option-icon install-option-icon--brand" aria-hidden="true"><img src="'+e+'" alt="" width="32" height="32" loading="lazy" decoding="async"></span><span class="install-option-body"><span class="install-option-title">Browser extension</span><span class="install-option-desc">Full control inside the browser.</span></span></a><a class="install-option-card" href="./standalone"><span class="install-option-icon install-option-icon--brand" aria-hidden="true"><img src="'+s+'" alt="" width="32" height="32" loading="lazy" decoding="async"></span><span class="install-option-body"><span class="install-option-title">Standalone app</span><span class="install-option-desc">For strict policies and any browser.</span></span></a></div><h2 id="which-option-should-i-choose" tabindex="-1">Which option should I choose? <a class="header-anchor" href="#which-option-should-i-choose" aria-label="Permalink to &quot;Which option should I choose?&quot;">​</a></h2><ul><li><strong>Chrome extension</strong> — when you need persistent access and the full feature set: auto-run, DevTools integration, and advanced in-browser workflows.</li><li><strong>Standalone application</strong> — when extensions cannot be installed, enterprise restrictions apply, or independent launch is required.</li></ul><hr><h2 id="storage" tabindex="-1">Where are settings stored? <a class="header-anchor" href="#storage" aria-label="Permalink to &quot;Where are settings stored? {#storage}&quot;">​</a></h2><p>Both the <strong>extension</strong> and <strong>standalone</strong> use <strong>a single shared settings profile</strong> for the browser: once saved in Options, the same values apply on <strong>every site</strong> where you open the inspector. No separate per-domain configuration is required.</p><p>Only the <strong>storage mechanism</strong> differs: the extension uses Chrome’s built-in storage for installed components, while standalone uses a <strong>dedicated local storage layer</strong> for the application (without installation in <code>chrome://extensions</code>), created specifically for this mode.</p><table tabindex="0"><thead><tr><th></th><th><strong>Extension</strong></th><th><strong>Standalone (bookmark)</strong></th></tr></thead><tbody><tr><td><strong>Settings</strong> (options, favorites, site lists, etc.)</td><td>The extension’s <strong>internal browser storage</strong> within the browser profile: data is tied to the installed Vue Inspector instance, not to a specific tab.</td><td><strong>Dedicated</strong> standalone local storage — same concept: one shared database for all sites launched through the bookmark.</td></tr><tr><td><strong>Customize assets</strong> (backgrounds, saved media from Customize and related UI)</td><td>Stored separately in <strong>browser storage</strong> under the extension context (files remain in the browser profile, not “on the site”).</td><td>Stored in the <strong>same unified</strong> standalone storage, subject to its limits (see <a href="/qa-tools/docs/options/customize.html">Customize</a>).</td></tr><tr><td><strong>Across sites</strong></td><td>One shared settings profile across all domains in the current browser profile.</td><td>One shared settings profile across all domains: storage is <strong>not bound</strong> to page origin, so reuse works the same way as in the extension.</td></tr></tbody></table><p>For media limits in Customize, see <a href="/qa-tools/docs/options/customize.html">Customize</a>.</p><p><strong>Saving and transfer:</strong> regular changes in Options <strong>autosave</strong> (with a small debounce). The <strong>extension</strong> stores settings in <strong>IndexedDB</strong> and <strong><code>chrome.storage.local</code></strong>; <strong>standalone</strong> keeps a snapshot in its <strong>central KV store</strong> (IndexedDB), while media is stored separately with a size limit. <strong>Export / Import / Reset</strong> in General provide JSON export and full reset; differences between modes during export and import are described in <a href="/qa-tools/docs/options/settings_management.html">Settings management</a>.</p>',13)])])}const b=o(i,[["render",l]]);export{f as __pageData,b as default};
